module bit_masking(
  input [31:0] data_in,
  input [15:0] mask,
  input enable,
  output [15:0] data_out
);

  reg [15:0] masked_result;

  always @(*) begin
    if (enable) begin
      masked_result = data_in & mask;
    end else begin
      masked_result = 16'b0;
    end
  end

  assign data_out = masked_result;

endmodule
